from datetime import datetime
from typing import Optional
from uuid import UUID

from pydantic import BaseModel, ConfigDict, EmailStr, Field, field_validator

from ..custom_types import UserRole
from ..utils.validators import validate_password_strength
from .descriptions import get_desc


class CreateUserRequest(BaseModel):
    """Request payload for creating a new user account."""

    email: EmailStr = Field(..., description=get_desc("user_s_email_address"))
    password: str = Field(
        ...,
        min_length=8,
        max_length=128,
        description=get_desc("user_s_password_minimum_8_characters"),
    )
    role: UserRole = Field(..., description=get_desc("user_s_role_determining_access_permissions"))
    first_name: Optional[str] = Field(
        None, max_length=100, description=get_desc("user_s_first_name")
    )
    last_name: Optional[str] = Field(
        None, max_length=100, description=get_desc("user_s_last_name")
    )

    @field_validator("email")
    @classmethod
    def normalize_email(cls, v):
        """Normalize email to lowercase to avoid case-sensitivity issues."""
        return v.lower().strip() if v else v

    @field_validator("password")
    def validate_password_strength(cls, v):
        """Validate password complexity before storing."""
        return validate_password_strength(v)


class UserProfile(BaseModel):
    """User profile data embedded in auth responses and returned by the users API."""

    id: str = Field(description=get_desc("unique_user_identifier"))
    email: EmailStr = Field(..., description=get_desc("user_s_email_address"))
    role: UserRole = Field(..., description=get_desc("user_s_role_determining_access_permissions"))
    first_name: Optional[str] = Field(
        None, max_length=100, description=get_desc("user_s_first_name")
    )
